// ---- Material 3 Components Overview ----
@Composable
fun Material3Components() {
    Column(
        modifier = Modifier
            .fillMaxSize()
            .padding(16.dp),
        verticalArrangement = Arrangement.spacedBy(16.dp)
    ) {
        // ---- TextField ----
        var text by remember { mutableStateOf("") }
        OutlinedTextField(
            value = text,
            onValueChange = { text = it },
            label = { Text("Enter text") },
            leadingIcon = {
                Icon(
                    imageVector = Icons.Default.Search,
                    contentDescription = "Search"
                )
            },
            modifier = Modifier.fillMaxWidth()
        )

        // ---- FilledTextField ----
        var filledText by remember { mutableStateOf("") }
        TextField(
            value = filledText,
            onValueChange = { filledText = it },
            label = { Text("Filled TextField") },
            colors = TextFieldDefaults.colors(
                focusedContainerColor = MaterialTheme.colorScheme.primaryContainer,
                unfocusedContainerColor = MaterialTheme.colorScheme.secondaryContainer
            )
        )

        // ---- DropdownMenu ----
        var expanded by remember { mutableStateOf(false) }
        var selectedOption by remember { mutableStateOf("Option 1") }

        Box {
            OutlinedButton(
                onClick = { expanded = true }
            ) {
                Text(selectedOption)
            }
            DropdownMenu(
                expanded = expanded,
                onDismissRequest = { expanded = false }
            ) {
                listOf("Option 1", "Option 2", "Option 3").forEach { option ->
                    DropdownMenuItem(
                        text = { Text(option) },
                        onClick = {
                            selectedOption = option
                            expanded = false
                        }
                    )
                }
            }
        }

        // ---- Switch ----
        var checked by remember { mutableStateOf(false) }
        Row(
            verticalAlignment = Alignment.CenterVertically
        ) {
            Text("Switch: ")
            Switch(
                checked = checked,
                onCheckedChange = { checked = it }
            )
            Spacer(modifier = Modifier.width(8.dp))
            Text(if (checked) "ON" else "OFF")
        }

        // ---- Slider ----
        var sliderValue by remember { mutableStateOf(0.5f) }
        Column {
            Text("Slider: ${(sliderValue * 100).toInt()}%")
            Slider(
                value = sliderValue,
                onValueChange = { sliderValue = it },
                colors = SliderDefaults.colors(
                    thumbColor = MaterialTheme.colorScheme.primary
                )
            )
        }

        // ---- ProgressIndicator ----
        var progress by remember { mutableStateOf(0.3f) }
        Column {
            LinearProgressIndicator(
                progress = progress,
                modifier = Modifier.fillMaxWidth()
            )
            CircularProgressIndicator(
                progress = progress,
                modifier = Modifier.size(48.dp)
            )
        }

        // ---- AlertDialog ----
        var showDialog by remember { mutableStateOf(false) }
        Button(
            onClick = { showDialog = true }
        ) {
            Text("Show Dialog")
        }

        if (showDialog) {
            AlertDialog(
                onDismissRequest = { showDialog = false },
                title = { Text("Alert Dialog") },
                text = { Text("This is an alert dialog") },
                confirmButton = {
                    TextButton(
                        onClick = { showDialog = false }
                    ) {
                        Text("OK")
                    }
                },
                dismissButton = {
                    TextButton(
                        onClick = { showDialog = false }
                    ) {
                        Text("Cancel")
                    }
                }
            )
        }

        // ---- Snackbar ----
        var snackbarState by remember { mutableStateOf(false) }
        Button(
            onClick = { snackbarState = true }
        ) {
            Text("Show Snackbar")
        }

        if (snackbarState) {
            Snackbar(
                modifier = Modifier.fillMaxWidth(),
                action = {
                    TextButton(
                        onClick = { snackbarState = false }
                    ) {
                        Text("Dismiss")
                    }
                }
            ) {
                Text("This is a snackbar")
            }
        }

        // ---- Card ----
        Card(
            modifier = Modifier.fillMaxWidth(),
            colors = CardDefaults.cardColors(
                containerColor = MaterialTheme.colorScheme.surfaceVariant
            )
        ) {
            Column(
                modifier = Modifier.padding(16.dp)
            ) {
                Text(
                    text = "Card Title",
                    fontSize = 18.sp,
                    fontWeight = FontWeight.Bold
                )
                Text(
                    text = "This is a Material 3 card with elevation.",
                    fontSize = 14.sp
                )
            }
        }
    }
}

